#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int packages = 0;
        int goodPieces = 0;
        for (int i = 0; i < N; i++) {
            if (goodPieces < A[i]) {
                packages++;
                goodPieces = K - 1;
            }
            goodPieces -= A[i];
            if (goodPieces < 0) goodPieces = 0;
        }
        printf("%d\n", packages);
    }
    return 0;
}

