import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int packages = 0;
            int goodPieces = 0;
            for (int i = 0; i < N; i++) {
                if (goodPieces < A[i]) {
                    packages++;
                    goodPieces = K - 1;
                }
                goodPieces -= A[i];
                if (goodPieces < 0) goodPieces = 0;
            }
            System.out.println(packages);
        }
    }
}

